var customer = {};
var sites = [];
var collections = [];
function toTitleCase(str) {
  return str.replace(/\w\S*/g, function (txt) {
    return txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase();
  });
}
function fmt(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function surveyBadge(status) {
  var map = {
    current: ['badge-current', 'Current'],
    due_soon: ['badge-due-soon', 'Due Soon'],
    expired: ['badge-expired', 'Expired'],
    no_survey: ['badge-no-survey', 'No Survey']
  };
  var cfg = map[status] || map.no_survey;
  return '<span class="badge ' + cfg[0] + '">' + cfg[1] + '</span>';
}
function msaBadge(msa) {
  var map = {
    Yes: 'badge-msa-yes',
    No: 'badge-msa-no',
    Pending: 'badge-msa-pending'
  };
  return '<span class="badge ' + (map[msa] || 'badge-no-survey') + '">' + (msa || '—') + '</span>';
}
function collectionStatusBadge(s) {
  var colors = {
    Booked: '#E6F1FB|#0C447C',
    Collected: '#E1F5EE|#085041',
    Complete: '#A3E851|#05042E',
    Cancelled: '#fee2e2|#991b1b'
  };
  var c = (colors[s] || '#f1efe8|#444441').split('|');
  return '<span style="font-size:10px;font-weight:600;padding:2px 8px;border-radius:20px;background:' + c[0] + ';color:' + c[1] + '">' + (s || '—') + '</span>';
}
function populateDetails(c) {
  if (!c) return;
  var hdrName = document.getElementById('hdr_name');
  var hdrDial = document.getElementById('hdr_dial');
  var hdrMsa = document.getElementById('hdr_msa');
  if (hdrName) hdrName.textContent = c.customer_name || 'Customer';
  if (hdrDial && c.dial_ref) {
    hdrDial.textContent = c.dial_ref;
    hdrDial.style.display = 'inline-block';
  }
  if (hdrMsa) hdrMsa.outerHTML; // replaced below
  document.getElementById('hdr_msa').className = 'badge ' + ({
    Yes: 'badge-msa-yes',
    No: 'badge-msa-no',
    Pending: 'badge-msa-pending'
  }[c.msa_signed] || 'badge-no-survey');
  document.getElementById('hdr_msa').textContent = c.msa_signed || '—';
  var fields = {
    e_customer_name: c.customer_name,
    e_contact_name: c.contact_name,
    e_job_title: c.job_title,
    e_contact_number: c.contact_number,
    e_email: c.email,
    e_dial_expiry: c.dial_expiry ? c.dial_expiry.split('T')[0] : '',
    e_address1: c.address1,
    e_address2: c.address2,
    e_city: c.city,
    e_postcode: c.postcode,
    e_default_instructions: c.default_instructions
  };
  Object.keys(fields).forEach(function (id) {
    var el = document.getElementById(id);
    if (el) el.value = fields[id] || '';
  });
  var dialEl = document.getElementById('e_dial_rating');
  var msaEl = document.getElementById('e_msa');
  var amEl = document.getElementById('e_account_manager');
  if (dialEl) dialEl.value = c.dial_ref || '';
  if (msaEl) msaEl.value = c.msa_signed || '';
  if (amEl) amEl.value = c.account_manager || '';
}
function renderSites(data) {
  var tbody = document.getElementById('sites_body');
  if (!tbody) return;
  if (!data.length) {
    tbody.innerHTML = '<tr><td colspan="5" class="empty">No sites yet</td></tr>';
    return;
  }
  tbody.innerHTML = data.map(function (s, i) {
    var addr = [s.address1, s.city].filter(Boolean).join(', ');
    return '<tr>' + '<td>' + (addr || '—') + '</td>' + '<td>' + (s.site_contact || '—') + '<br><span style="font-size:11px;color:#888780">' + (s.contact_email || '') + '</span></td>' + '<td>' + surveyBadge(s.survey_status) + '</td>' + '<td>' + fmt(s.review_due) + '</td>' + '<td style="display:flex;gap:6px">' + '<button class="btn-sm btn-sm-edit" onclick="window.viewSite(' + i + ')">View</button>' + '</td>' + '</tr>';
  }).join('');
}
function renderCollections(data) {
  var tbody = document.getElementById('collections_body');
  if (!tbody) return;
  if (!data.length) {
    tbody.innerHTML = '<tr><td colspan="6" class="empty">No collections yet</td></tr>';
    return;
  }
  tbody.innerHTML = data.map(function (c) {
    return '<tr>' + '<td><span class="collection-ref">' + c.collection_id + '</span></td>' + '<td>' + fmt(c.collection_date) + '</td>' + '<td>' + (c.address1 || '—') + '</td>' + '<td>' + collectionStatusBadge(c.status) + '</td>' + '<td>' + (c.asset_count || 0) + '</td>' + '<td><button class="btn-sm btn-sm-edit" onclick="window.viewCollection(' + c.collection_id + ')">View</button></td>' + '</tr>';
  }).join('');
}
function render(model) {
  customer = model.customer || {};
  sites = model.sites || [];
  collections = model.collections || [];
  populateDetails(customer);
  renderSites(sites);
  renderCollections(collections);
}
window.setTab = function (tab) {
  document.querySelectorAll('.tab').forEach(function (t, i) {
    t.className = 'tab' + (['details', 'sites', 'collections'][i] === tab ? ' active' : '');
  });
  document.querySelectorAll('.tab-content').forEach(function (c, i) {
    c.className = 'tab-content' + (['details', 'sites', 'collections'][i] === tab ? ' active' : '');
  });
};
window.goBack = function () {
  appsmith.triggerEvent('onGoBack');
};
window.saveDetails = function () {
  appsmith.updateModel({
    customer_name: document.getElementById('e_customer_name').value,
    contact_name: document.getElementById('e_contact_name').value,
    job_title: document.getElementById('e_job_title').value,
    contact_number: document.getElementById('e_contact_number').value,
    email: document.getElementById('e_email').value,
    dial_rating: document.getElementById('e_dial_rating').value,
    dial_expiry: document.getElementById('e_dial_expiry').value || null,
    msa_signed: document.getElementById('e_msa').value,
    account_manager: document.getElementById('e_account_manager').value,
    default_instructions: document.getElementById('e_default_instructions').value,
    address1: document.getElementById('e_address1').value,
    address2: document.getElementById('e_address2').value,
    city: document.getElementById('e_city').value,
    postcode: document.getElementById('e_postcode').value
  });
  appsmith.triggerEvent('onSaveCustomer');
};
window.resetDetails = function () {
  populateDetails(customer);
};
window.openSiteForm = function () {
  ['sf_address1', 'sf_address2', 'sf_city', 'sf_postcode', 'sf_site_contact', 'sf_phone', 'sf_email'].forEach(function (id) {
    var el = document.getElementById(id);
    if (el) el.value = '';
  });
  document.getElementById('site_form').classList.add('open');
};
window.closeSiteForm = function () {
  document.getElementById('site_form').classList.remove('open');
};
window.saveSite = function () {
  appsmith.updateModel({
    address1: document.getElementById('sf_address1').value,
    address2: document.getElementById('sf_address2').value,
    city: document.getElementById('sf_city').value,
    postcode: document.getElementById('sf_postcode').value,
    site_contact: document.getElementById('sf_site_contact').value,
    site_phone: document.getElementById('sf_phone').value,
    site_email: document.getElementById('sf_email').value
  });
  appsmith.triggerEvent('onSaveSite');
  window.closeSiteForm();
};
window.viewSite = function (i) {
  var s = sites[i];
  if (!s) return;
  appsmith.updateModel({
    selected_site: s
  });
  appsmith.triggerEvent('onViewSite');
};
window.viewCollection = function (id) {
  appsmith.updateModel({
    selected_collection_id: id
  });
  appsmith.triggerEvent('onViewCollection');
};
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  render(model);
});

